#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long A[105], B[105];
        for(int i=0;i<N;i++) scanf("%lld", &A[i]);
        for(int i=0;i<N;i++) scanf("%lld", &B[i]);
        int happy=0;
        for(int i=0;i<N;i++){
            long long mx = A[i] > B[i] ? A[i] : B[i];
            long long mn = A[i] < B[i] ? A[i] : B[i];
            if(mx <= 2*mn) happy++;
        }
        printf("%d\n", happy);
    }
    return 0;
}

