#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        A = [next(it) for _ in range(N)]
        B = [next(it) for _ in range(N)]
        happy = 0
        for a, b in zip(A, B):
            mx = a if a > b else b
            mn = a if a < b else b
            if mx <= 2 * mn:
                happy += 1
        out_lines.append(str(happy))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

